// Node structure for the binary tree
struct Node {
    int data;
    struct Node* left;
    struct Node* right;
};

// Function to create a new node
struct Node* newNode(int data) {
    struct Node* node = (struct Node*)malloc(sizeof(struct Node));
    node->data = data;
    node->left = NULL;
    node->right = NULL;
    return node;
}

// Function to return the bottom view of the binary tree
void bottomView(struct Node* root) {
    if (root == NULL) return;

    std::queue<std::pair<struct Node*, int>> q;
    q.push({root, 0});

    std::map<int, int> mpp;

    while (!q.empty()) {
        auto it = q.front();
        q.pop();
        struct Node* node = it.first;
        int line = it.second;

        mpp[line] = node->data;

        if (node->left != NULL) q.push({node->left, line - 1});
        if (node->right != NULL) q.push({node->right, line + 1});
    }

    for (auto it : mpp) {
        printf("%d ", it.second);
    }
}

